// ─────────────────────────────────────────────────────────────────
// NODE 5: DATA NORMALIZATION
// Merges sales, inventory, and catalog into one clean dataset per SKU
// ─────────────────────────────────────────────────────────────────

const salesRaw     = $('Fetch Sales History (Google Sheets)').all();
const inventoryRaw = $('Fetch Current Inventory').all();
const catalogRaw   = $('Fetch Product Catalog').all();

// Build lookup maps
const inventoryMap = {};
for (const row of inventoryRaw) {
  const d = row.json;
  inventoryMap[d.sku] = {
    currentStock: parseFloat(d.current_stock) || 0
  };
}

const catalogMap = {};
for (const row of catalogRaw) {
  const d = row.json;
  catalogMap[d.sku] = {
    name:         d.product_name || d.sku,
    supplier:     d.supplier     || 'Unknown',
    leadTimeDays: parseFloat(d.lead_time_days) || 7,
    unitCost:     parseFloat(d.unit_cost)      || 0,
    reorderUnit:  parseFloat(d.reorder_unit)   || 1
  };
}

// Group sales by SKU — normalize date and units
const salesBySku = {};
for (const row of salesRaw) {
  const d = row.json;
  const sku = d.sku;
  if (!sku) continue;

  const saleDate = new Date(d.sale_date || d.date);
  const qty      = parseFloat(d.quantity_sold || d.qty) || 0;
  if (isNaN(saleDate.getTime()) || qty <= 0) continue;

  if (!salesBySku[sku]) salesBySku[sku] = [];
  salesBySku[sku].push({ date: saleDate, qty });
}

// Assemble normalized dataset
const result = [];
for (const sku of Object.keys(salesBySku)) {
  const sales   = salesBySku[sku].sort((a, b) => a.date - b.date);
  const inv     = inventoryMap[sku]  || { currentStock: 0 };
  const catalog = catalogMap[sku]    || { name: sku, leadTimeDays: 7, unitCost: 0, supplier: 'Unknown', reorderUnit: 1 };

  result.push({
    json: {
      sku,
      productName:  catalog.name,
      supplier:     catalog.supplier,
      leadTimeDays: catalog.leadTimeDays,
      unitCost:     catalog.unitCost,
      reorderUnit:  catalog.reorderUnit,
      currentStock: inv.currentStock,
      salesHistory: sales.map(s => ({ date: s.date.toISOString().split('T')[0], qty: s.qty }))
    }
  });
}

return result;

// ─────────────────────────────────────────────────────────────────
// NODE 6: DEMAND ANALYSIS
// Calculates average daily/weekly demand, moving averages,
// trend direction, and classifies products as fast/slow movers
// ─────────────────────────────────────────────────────────────────

const items = $input.all();
const results = [];

for (const item of items) {
  const d = item.json;
  const history = d.salesHistory || [];

  if (history.length === 0) {
    results.push({ json: { ...d, demandAnalysis: null, warning: 'No sales history' } });
    continue;
  }

  // ── Total period span
  const dates     = history.map(h => new Date(h.date));
  const minDate   = new Date(Math.min(...dates));
  const maxDate   = new Date(Math.max(...dates));
  const spanDays  = Math.max(1, (maxDate - minDate) / (1000 * 60 * 60 * 24) + 1);
  const totalQty  = history.reduce((s, h) => s + h.qty, 0);

  // ── Average daily demand
  const avgDailyDemand  = totalQty / spanDays;
  const avgWeeklyDemand = avgDailyDemand * 7;

  // ── Simple Moving Average (last 4 weeks = 28 days)
  const now          = new Date();
  const cutoff28     = new Date(now - 28 * 86400000);
  const last28       = history.filter(h => new Date(h.date) >= cutoff28);
  const sma28        = last28.length > 0
    ? last28.reduce((s, h) => s + h.qty, 0) / 28
    : avgDailyDemand;

  // ── Weighted Moving Average (more weight on recent weeks)
  // Weights: W1=0.5 (most recent 7d), W2=0.3 (8-14d), W3=0.2 (15-21d)
  const w = [{ days: 7, w: 0.5 }, { days: 14, w: 0.3 }, { days: 21, w: 0.2 }];
  let wmaSum = 0, wmaTotal = 0;
  for (const band of w) {
    const from   = new Date(now - band.days * 86400000);
    const prev   = new Date(now - (band.days - 7) * 86400000);
    const slice  = history.filter(h => {
      const d = new Date(h.date);
      return d >= from && d < prev;
    });
    const sliceQty = slice.reduce((s, h) => s + h.qty, 0);
    wmaSum  += sliceQty * band.w;
    wmaTotal += band.w;
  }
  const wmaDaily = wmaTotal > 0 ? wmaSum / wmaTotal / 7 : avgDailyDemand;

  // ── Trend direction (compare first-half vs second-half avg)
  const midIndex    = Math.floor(history.length / 2);
  const firstHalf   = history.slice(0, midIndex);
  const secondHalf  = history.slice(midIndex);
  const firstAvg    = firstHalf.reduce((s, h)  => s + h.qty, 0) / Math.max(1, firstHalf.length);
  const secondAvg   = secondHalf.reduce((s, h) => s + h.qty, 0) / Math.max(1, secondHalf.length);
  const trendPct    = firstAvg > 0 ? ((secondAvg - firstAvg) / firstAvg) * 100 : 0;
  const trendDir    = trendPct > 5 ? 'upward' : trendPct < -5 ? 'downward' : 'stable';

  // ── Standard deviation (for safety stock)
  const dailySales = history.map(h => h.qty);
  const mean       = dailySales.reduce((s, v) => s + v, 0) / dailySales.length;
  const variance   = dailySales.reduce((s, v) => s + Math.pow(v - mean, 2), 0) / dailySales.length;
  const stdDev     = Math.sqrt(variance);

  // ── Fast mover classification (top 20% by avg daily demand)
  const fastMoverThreshold = 5; // units/day — adjust per business
  const isFastMover        = avgDailyDemand >= fastMoverThreshold;

  results.push({
    json: {
      ...d,
      demandAnalysis: {
        avgDailyDemand:  Math.round(avgDailyDemand  * 100) / 100,
        avgWeeklyDemand: Math.round(avgWeeklyDemand * 100) / 100,
        smaDaily:        Math.round(sma28           * 100) / 100,
        wmaDaily:        Math.round(wmaDaily         * 100) / 100,
        trendDirection:  trendDir,
        trendPercent:    Math.round(trendPct),
        stdDev:          Math.round(stdDev * 100) / 100,
        spanDays:        Math.round(spanDays),
        isFastMover,
        dataPoints:      history.length
      }
    }
  });
}

return results;

// ─────────────────────────────────────────────────────────────────
// NODE 7: DEMAND FORECASTING
// Produces next-period demand forecast using WMA as primary model
// with optional linear regression trend adjustment
// ─────────────────────────────────────────────────────────────────

const FORECAST_DAYS   = 7;  // Forecast horizon (days)
const Z_SCORE         = 1.645; // 95% service level for safety stock
const BUFFER_MULTIPLIER = 1.2; // 20% buffer on top of forecast

const items = $input.all();
const results = [];

for (const item of items) {
  const d  = item.json;
  const da = d.demandAnalysis;

  if (!da) {
    results.push({ json: { ...d, forecast: null } });
    continue;
  }

  // ── Primary forecast: Weighted Moving Average daily
  const wmaForecast   = da.wmaDaily * FORECAST_DAYS;

  // ── Secondary: Simple Moving Average
  const smaForecast   = da.smaDaily * FORECAST_DAYS;

  // ── Linear Regression Trend Adjustment
  // Fit a line through weekly aggregated sales and project forward
  const history = d.salesHistory || [];
  let linearForecast = wmaForecast; // fallback

  if (history.length >= 14) {
    // Aggregate into weekly buckets
    const weeklyMap = {};
    for (const h of history) {
      const weekNum = Math.floor(new Date(h.date).getTime() / (7 * 86400000));
      weeklyMap[weekNum] = (weeklyMap[weekNum] || 0) + h.qty;
    }
    const weeks   = Object.keys(weeklyMap).sort();
    const n       = weeks.length;
    const xVals   = weeks.map((_, i) => i);
    const yVals   = weeks.map(w => weeklyMap[w]);
    const sumX    = xVals.reduce((s, v) => s + v, 0);
    const sumY    = yVals.reduce((s, v) => s + v, 0);
    const sumXY   = xVals.reduce((s, v, i) => s + v * yVals[i], 0);
    const sumX2   = xVals.reduce((s, v) => s + v * v, 0);
    const slope   = (n * sumXY - sumX * sumY) / (n * sumX2 - sumX * sumX || 1);
    const intercept = (sumY - slope * sumX) / n;
    const projectedWeekly = Math.max(0, intercept + slope * n); // next week
    linearForecast = projectedWeekly * (FORECAST_DAYS / 7);
  }

  // ── Ensemble: blend WMA (60%) + Linear (40%) for final forecast
  const blendedForecast = 0.6 * wmaForecast + 0.4 * linearForecast;

  // ── Safety stock: Z * stdDev * sqrt(leadTime)
  const safetyStock = Math.ceil(
    Z_SCORE * da.stdDev * Math.sqrt(d.leadTimeDays)
  );

  // ── Reorder Point
  // ROP = (avg daily demand × lead time) + safety stock
  const avgDaily = da.wmaDaily || da.avgDailyDemand;
  const rop      = Math.ceil(avgDaily * d.leadTimeDays + safetyStock);

  // ── Days of Inventory Remaining
  const daysRemaining = avgDaily > 0
    ? Math.floor(d.currentStock / avgDaily)
    : 999;

  // ── Recommended Order Quantity
  // EOQ (simplified) = sqrt(2 * D * S / H)
  // D = annual demand, S = order cost (assumed $50), H = holding cost (20% of unit cost)
  const annualDemand = avgDaily * 365;
  const orderCost    = 50;
  const holdingCost  = Math.max(0.5, d.unitCost * 0.20);
  const eoq          = Math.ceil(Math.sqrt(2 * annualDemand * orderCost / holdingCost));

  // Simple rule fallback: forecast for next cycle + buffer
  const simpleOrder  = Math.ceil(blendedForecast * BUFFER_MULTIPLIER);
  const orderQty     = d.unitCost > 0 ? eoq : simpleOrder;

  results.push({
    json: {
      ...d,
      forecast: {
        horizonDays:      FORECAST_DAYS,
        wmaForecast:      Math.round(wmaForecast),
        smaForecast:      Math.round(smaForecast),
        linearForecast:   Math.round(linearForecast),
        blendedForecast:  Math.round(blendedForecast),
        safetyStock,
        rop,
        daysRemaining,
        orderQty,
        eoq
      }
    }
  });
}

return results;

// ─────────────────────────────────────────────────────────────────
// NODE 8: RESTOCK DECISION ENGINE
// Determines if a restock alert should be triggered and assigns
// urgency level: critical / medium / low / none
// Also generates human-readable insight messages
// ─────────────────────────────────────────────────────────────────

const items = $input.all();
const results = [];

for (const item of items) {
  const d  = item.json;
  const fc = d.forecast;
  const da = d.demandAnalysis;

  if (!fc || !da) {
    results.push({ json: { ...d, decision: { alert: false, urgency: 'none', reason: 'Insufficient data' } } });
    continue;
  }

  const { currentStock, sku, productName, leadTimeDays } = d;
  const { rop, daysRemaining, blendedForecast, orderQty, safetyStock } = fc;

  let urgency    = 'none';
  let alert      = false;
  let reason     = '';
  let insights   = [];

  // ── Rule 1: Stock at or below ROP
  if (currentStock <= rop) {
    alert = true;
    if (currentStock <= safetyStock) {
      urgency = 'critical';
      reason  = `Stock (${currentStock}) is at or below safety stock (${safetyStock}). Stockout imminent.`;
    } else {
      urgency = 'medium';
      reason  = `Stock (${currentStock}) has crossed reorder point (${rop}).`;
    }
  }

  // ── Rule 2: Will stock out before next delivery arrives?
  if (daysRemaining < leadTimeDays) {
    alert   = true;
    urgency = urgency === 'critical' ? 'critical' : 'critical';
    reason += ` Predicted stockout in ${daysRemaining} day(s) — lead time is ${leadTimeDays} day(s).`;
  }

  // ── Rule 3: Low urgency — within 3x lead time of ROP
  if (!alert && currentStock <= rop * 1.5) {
    alert   = true;
    urgency = 'low';
    reason  = `Stock (${currentStock}) approaching reorder point (${rop}). Plan ahead.`;
  }

  // ── Insight messages
  if (daysRemaining < leadTimeDays) {
    insights.push(`⚠️ ${productName} will stock out in ${daysRemaining} day(s) — order NOW to cover lead time.`);
  } else if (daysRemaining <= 14) {
    insights.push(`📦 ${productName} has ~${daysRemaining} days of stock remaining.`);
  }

  if (da.trendDirection === 'upward') {
    insights.push(`📈 Demand trending up ${da.trendPercent}% — consider increasing order qty.`);
  } else if (da.trendDirection === 'downward') {
    insights.push(`📉 Demand trending down ${Math.abs(da.trendPercent)}% — monitor for overstock risk.`);
  }

  // ── Overstock detection
  const avgDaily   = da.wmaDaily || da.avgDailyDemand;
  const coverDays  = avgDaily > 0 ? currentStock / avgDaily : 999;
  if (coverDays > 90 && !alert) {
    insights.push(`⚡ ${productName} is overstocked (${Math.round(coverDays)} days of supply). Reduce next order.`);
  }

  results.push({
    json: {
      ...d,
      decision: {
        alert,
        urgency,
        reason: reason.trim(),
        insights,
        coverDays: Math.round(coverDays)
      }
    }
  });
}

return results;

// ─────────────────────────────────────────────────────────────────
// NODE 10: DUPLICATE ALERT PREVENTION
// Checks last alert timestamp. Skip if alert was sent < 24h ago.
// In production: read from a database or Sheets log.
// ─────────────────────────────────────────────────────────────────
const items = $input.all();
const results = [];

for (const item of items) {
  const d = item.json;
  // TODO: Replace with real DB lookup using $('Read Alert Log').item
  const lastAlertSent = d.lastAlertSent ? new Date(d.lastAlertSent) : null;
  const hoursSince = lastAlertSent
    ? (Date.now() - lastAlertSent.getTime()) / 3600000
    : 999;

  if (hoursSince >= 24) {
    results.push({ json: { ...d, _shouldSendAlert: true } });
  }
  // Items with recent alerts are silently dropped
}

return results;

// ─────────────────────────────────────────────────────────────────
// NODE 11: FORMAT ALERT MESSAGE
// Builds a rich, readable alert message for all channels
// ─────────────────────────────────────────────────────────────────
const items = $input.all();
const results = [];

const URGENCY_EMOJI = { critical: '🔴', medium: '🟡', low: '🟢', none: '⚪' };

for (const item of items) {
  const d   = item.json;
  const fc  = d.forecast;
  const da  = d.demandAnalysis;
  const dec = d.decision;

  const emoji    = URGENCY_EMOJI[dec.urgency] || '⚪';
  const dateStr  = new Date().toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' });

  const insightBlock = dec.insights.length
    ? '\n\n*Insights:*\n' + dec.insights.join('\n')
    : '';

  const slackMsg = [
    `${emoji} *RESTOCK ALERT — ${dec.urgency.toUpperCase()}*`,
    `*Date:* ${dateStr}`,
    `*SKU:* ${d.sku}  |  *Product:* ${d.productName}`,
    `*Supplier:* ${d.supplier}  |  *Lead Time:* ${d.leadTimeDays} day(s)`,
    `*Current Stock:* ${d.currentStock} units`,
    `*Reorder Point (ROP):* ${fc.rop} units`,
    `*Safety Stock:* ${fc.safetyStock} units`,
    `*Days Remaining:* ${fc.daysRemaining} day(s)`,
    `*Forecast (next ${fc.horizonDays}d):* ${fc.blendedForecast} units`,
    `*Recommended Order Qty:* ${fc.orderQty} units`,
    `*Reason:* ${dec.reason}`,
    insightBlock
  ].join('\n');

  const emailHtml = `
<h2 style="color:#e53e3e">${emoji} Restock Alert — ${dec.urgency.toUpperCase()}</h2>
<p><strong>Date:</strong> ${dateStr}</p>
<table cellpadding="6" cellspacing="0" border="1" style="border-collapse:collapse;font-family:sans-serif;font-size:14px">
  <tr><td><strong>SKU</strong></td><td>${d.sku}</td><td><strong>Product</strong></td><td>${d.productName}</td></tr>
  <tr><td><strong>Supplier</strong></td><td>${d.supplier}</td><td><strong>Lead Time</strong></td><td>${d.leadTimeDays} days</td></tr>
  <tr style="background:#fff5f5"><td><strong>Current Stock</strong></td><td>${d.currentStock}</td><td><strong>ROP</strong></td><td>${fc.rop}</td></tr>
  <tr><td><strong>Safety Stock</strong></td><td>${fc.safetyStock}</td><td><strong>Days Remaining</strong></td><td>${fc.daysRemaining}</td></tr>
  <tr style="background:#f0fff4"><td><strong>Forecast (${fc.horizonDays}d)</strong></td><td>${fc.blendedForecast} units</td><td><strong>Order Qty</strong></td><td><strong>${fc.orderQty} units</strong></td></tr>
</table>
<p><em>${dec.reason}</em></p>
${dec.insights.map(i => `<p>${i}</p>`).join('')}
`;

  const telegramMsg = `${emoji} *Restock Alert — ${dec.urgency.toUpperCase()}*\n` +
    `SKU: ${d.sku} | ${d.productName}\n` +
    `Stock: ${d.currentStock} | ROP: ${fc.rop}\n` +
    `Days left: ${fc.daysRemaining} | Order: *${fc.orderQty} units*\n` +
    `${dec.reason}`;

  results.push({
    json: {
      ...d,
      alerts: { slackMsg, emailHtml, telegramMsg }
    }
  });
}

return results;

// ─────────────────────────────────────────────────────────────────
// NODE 17: LOG ALL (no-alert path)
// Items that don't need an alert still get logged to ForecastLog
// ─────────────────────────────────────────────────────────────────
const items = $input.all();
return items.map(item => ({
  json: {
    ...item.json,
    _loggedAt: new Date().toISOString()
  }
}));
